import{_ as e}from"./chunks/energy-icon.CJ0lPSJi.js";import{_ as a,o as t,c as o,a4 as n}from"./chunks/framework.BMymQDdR.js";const b=JSON.parse('{"title":"What is energy？","description":"","frontmatter":{},"headers":[],"relativePath":"en/course/what-is-energy.md","filePath":"en/course/what-is-energy.md","lastUpdated":1731232060000}'),i={name:"en/course/what-is-energy.md"},r=n('<h1 id="what-is-energy" tabindex="-1">What is energy？ <a class="header-anchor" href="#what-is-energy" aria-label="Permalink to &quot;What is energy？&quot;">​</a></h1><p align="center"><img src="'+e+'"></p><p align="center" style="font-size:24px;"><strong> Energy is Go&#39;s framework for building desktop applications based on CEF </strong></p><h3 id="introduce" tabindex="-1">Introduce <a class="header-anchor" href="#introduce" aria-label="Permalink to &quot;Introduce&quot;">​</a></h3><blockquote><p>energy is Go based <a href="https://gitlab.com/freepascal.org/lazarus/lazarus" target="_blank" rel="noreferrer">LCL</a> and <a href="https://github.com/chromiumembedded/cef" target="_blank" rel="noreferrer">CEF</a>(Chromium Embedded Framework) Developed framework</p><p>Build cross platform desktop applications that support Windows, Linux, and MacOS using Go and web technologies (HTML+CSS+JavaScript)</p></blockquote><blockquote><ul><li>Rich CEF API and native widgets for LCL system</li><li>The development environment is simple, the compilation speed is fast, and only Go and Energy rely on the CEF binary framework</li><li>Cross platform: One set of code can be packaged into Windows, domestic UOS Deepin、Kylin, MacOS, Linux</li><li>responsibility</li></ul><blockquote><ul><li>Go: Go is responsible for window creation, CEF configuration and functionality implementation, as well as the creation of various UI components.</li><li>Web: HTML + CSS + JavaScript are responsible for the functionality of the client-side interface, allowing you to create any interface you desire.</li></ul></blockquote><ul><li>Front-end technology: Any front-end technologies and frameworks, such as Vue, React, Angular, as well as native HTML + CSS + JS, can be utilized.</li><li>Event driven: Event-driven and based on IPC (Inter-Process Communication), it achieves swift invocation and data interaction between Go and the web end.</li><li>Resource loading: can directly read local resources or resources built into execution files without http service support, and also support http service loading resources</li></ul></blockquote><h3 id="use" tabindex="-1">Use <a class="header-anchor" href="#use" aria-label="Permalink to &quot;Use&quot;">​</a></h3><p>energy CEF supports not just web-based applications, as it has capabilities beyond embedding web pages. It leverages the Webkit engine and takes advantage of HTML5 features implemented in Chrome, and in terms of performance, it also closely resembles Chrome.</p><p>Custom plugins, custom protocols, custom JavaScript objects and extensions, and controlled operations like resource loading, navigation, context menus, response filtering, cookie management, and more are also feasible.</p><p>LCL (Lazarus Component Library) provides native system UI widgets and facilitates cross-platform development. By combining LCL with CEF, applications with diverse interfaces can be created.</p>',10),s=[r];function l(c,d,p,u,m,h){return t(),o("div",null,s)}const y=a(i,[["render",l]]);export{b as __pageData,y as default};
